import "./Footer.css";


const Footer = () => {
    return(
        <div>
            <div className="footer-bg-container">
                <h2 className="address">123, Main Street, City Name, State Name <br/> +19920-123-456, +19920-123-456 <br/>viren@vancotech.com</h2>
            </div>

            <div>
                <h1>OPENING TIMES</h1>

                <p>Saturday - Sunday <br/>11:00 AM To 12:00 PM</p>
                <p>Monday - Friday <br/>09:00 AM To 10:00 PM</p>
            </div>

            <div>
                <h1>THE MENU</h1>

                <p></p>
            </div>
        </div>
    )
}

export default Footer;
